grammar PL;

@header {
package mygrammar;
}

program	   : statement+
	       ;

statement  : assignment
	       | print
	       | function_call
	       | for_loop
	       | COMMENT
	       ;

assignment : ID '=' expression
	       ;

expression : string_concatenation
	       | ID
	       ;

string_concatenation : expression '++' expression
	       ;

print      : 'print' expression
	       ;

function_definition : 'function' ID '(' function_params ')' '{' statement+ '}'
	           ;

function_params : ID (',' ID)*
	           ;

function_call : ID '(' function_call_params? ')'
	           ;

function_call_params : expression (',' expression)*
	              ;

for_loop   : 'for' ID 'in' INT '..' INT '{' statement+ '}'
	       ;

ID	   : [a-z_A-Z]([a-z_A-Z0-9]+)?;

INT        : [0-9]+;

COMMENT    : '//' ~[\n\r]* -> skip;

WS 	   : [ \t\r\n]+ -> skip;

```

